class TransactionProcessor {
    static let shared = TransactionProcessor()
    
    private var accounts: [String: Account] = [:]
    private var transactionHistory: [Transaction] = []
    private let processingQueue = DispatchQueue(label: "com.bankingapp.transactionProcessing", qos: .userInitiated)
    
    private init() {
        loadAccounts()
    }
    
    private func loadAccounts() {
        accounts["ACC001"] = Account(accountNumber: "ACC001", balance: 5000.00, accountHolderName: "John Doe", accountType: .checking)
        accounts["ACC002"] = Account(accountNumber: "ACC002", balance: 10000.00, accountHolderName: "Jane Smith", accountType: .savings)
    }
    
    func processTransaction(fromAccount: String, toAccount: String, amount: Decimal, description: String, completion: @escaping (Result<Transaction, TransactionError>) -> Void) {
        processingQueue.async { [weak self] in
            guard let self = self else { return }
            
            guard let sender = self.accounts[fromAccount] else {
                DispatchQueue.main.async {
                    completion(.failure(.accountNotFound))
                }
                return
            }
            
            guard self.accounts[toAccount] != nil else {
                DispatchQueue.main.async {
                    completion(.failure(.recipientNotFound))
                }
                return
            }
            
            guard amount > 0 else {
                DispatchQueue.main.async {
                    completion(.failure(.invalidAmount))
                }
                return
            }
            
            guard sender.balance >= amount else {
                DispatchQueue.main.async {
                    completion(.failure(.insufficientFunds))
                }
                return
            }
            
            self.accounts[fromAccount]?.balance -= amount
            self.accounts[toAccount]?.balance += amount
            
            let transaction = Transaction(
                id: UUID().uuidString,
                fromAccount: fromAccount,
                toAccount: toAccount,
                amount: amount,
                timestamp: Date(),
                type: .transfer,
                status: .completed,
                description: description
            )
            
            self.transactionHistory.append(transaction)
            self.saveTransactionHistory()
            
            DispatchQueue.main.async {
                completion(.success(transaction))
            }
        }
    }
    
    func getBalance(accountNumber: String) -> Decimal? {
        return accounts[accountNumber]?.balance
    }
    
    func getAccount(accountNumber: String) -> Account? {
        return accounts[accountNumber]
    }
    
    func getTransactionHistory(accountNumber: String) -> [Transaction] {
        return transactionHistory.filter { $0.fromAccount == accountNumber || $0.toAccount == accountNumber }
    }
    
    private func saveTransactionHistory() {
        let encoder = JSONEncoder()
        if let encoded = try? encoder.encode(transactionHistory.map { TransactionDTO(transaction: $0) }) {
            _ = SecureStorage.shared.saveSecureData(encoded, key: "transactionHistory")
        }
    }
    
    enum TransactionError: Error {
        case accountNotFound
        case recipientNotFound
        case insufficientFunds
        case invalidAmount
        case networkError
        case processingError
    }
}

