class TransferViewController: UIViewController {
    private let fromAccountField = UITextField()
    private let toAccountField = UITextField()
    private let amountField = UITextField()
    private let descriptionField = UITextField()
    private let transferButton = UIButton(type: .system)
    private let activityIndicator = UIActivityIndicatorView(style: .medium)
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        title = "Transfer Funds"
        
        let stackView = UIStackView()
        stackView.axis = .vertical
        stackView.spacing = 16
        stackView.translatesAutoresizingMaskIntoConstraints = false
        
        fromAccountField.placeholder = "From Account"
        fromAccountField.borderStyle = .roundedRect
        fromAccountField.autocapitalizationType = .allCharacters
        
        toAccountField.placeholder = "To Account"
        toAccountField.borderStyle = .roundedRect
        toAccountField.autocapitalizationType = .allCharacters
        
        amountField.placeholder = "Amount"
        amountField.borderStyle = .roundedRect
        amountField.keyboardType = .decimalPad
        
        descriptionField.placeholder = "Description"
        descriptionField.borderStyle = .roundedRect
        
        transferButton.setTitle("Transfer", for: .normal)
        transferButton.backgroundColor = .systemBlue
        transferButton.setTitleColor(.white, for: .normal)
        transferButton.layer.cornerRadius = 8
        transferButton.addTarget(self, action: #selector(transferTapped), for: .touchUpInside)
        
        activityIndicator.hidesWhenStopped = true
        activityIndicator.translatesAutoresizingMaskIntoConstraints = false
        
        stackView.addArrangedSubview(fromAccountField)
        stackView.addArrangedSubview(toAccountField)
        stackView.addArrangedSubview(amountField)
        stackView.addArrangedSubview(descriptionField)
        stackView.addArrangedSubview(transferButton)
        
        view.addSubview(stackView)
        view.addSubview(activityIndicator)
        
        NSLayoutConstraint.activate([
            stackView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 40),
            stackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            stackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            
            transferButton.heightAnchor.constraint(equalToConstant: 50),
            
            activityIndicator.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            activityIndicator.topAnchor.constraint(equalTo: stackView.bottomAnchor, constant: 20)
        ])
    }
    
    @objc private func transferTapped() {
        guard let fromAccount = fromAccountField.text, !fromAccount.isEmpty,
              let toAccount = toAccountField.text, !toAccount.isEmpty,
              let amountString = amountField.text, !amountString.isEmpty,
              let amount = Decimal(string: amountString),
              let description = descriptionField.text, !description.isEmpty else {
            showAlert(message: "Please fill in all fields")
            return
        }
        
        activityIndicator.startAnimating()
        transferButton.isEnabled = false
        
        TransactionProcessor.shared.processTransaction(
            fromAccount: fromAccount,
            toAccount: toAccount,
            amount: amount,
            description: description
        ) { [weak self] result in
            self?.activityIndicator.stopAnimating()
            self?.transferButton.isEnabled = true
            
            switch result {
            case .success(let transaction):
                self?.showAlert(message: "Transfer successful! Transaction ID: \(transaction.id)")
                self?.clearFields()
            case .failure(let error):
                self?.showAlert(message: "Transfer failed: \(error.localizedDescription)")
            }
        }
    }
    
    private func clearFields() {
        fromAccountField.text = ""
        toAccountField.text = ""
        amountField.text = ""
        descriptionField.text = ""
    }
    
    private func showAlert(message: String) {
        let alert = UIAlertController(title: "Transaction", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

